import React, { useState, useEffect } from 'react';
import './Projects.css';

interface Project {
  _id?: string;
  title: string;
  description: string;
  technologies: string[];
  liveUrl: string;
  githubUrl: string;
  imageUrl: string;
  featured: boolean;
}

const Projects: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>([
    {
      title: 'QUICKART',
      description: 'Developed a full-featured e-commerce web application using Django. Implemented features such as login/logout, signup, order placing with existing or new addresses, order tracking, and a beautiful user interface. Classified products into different categories for easy navigation and browsing.',
      technologies: ['HTML', 'CSS', 'JavaScript', 'Django'],
      liveUrl: 'https://example-quickart.com',
      githubUrl: 'https://github.com/username/quickart',
      imageUrl: '/project1.jpg',
      featured: true
    },
    {
      title: 'E-Commerce Platform',
      description: 'A full-featured e-commerce platform with user authentication, product management, shopping cart, and payment integration. Built with modern web technologies for optimal performance and user experience.',
      technologies: ['React', 'Node.js', 'MongoDB', 'Express.js', 'Stripe API'],
      liveUrl: 'https://example-ecommerce.com',
      githubUrl: 'https://github.com/username/ecommerce-platform',
      imageUrl: '/project2.jpg',
      featured: true
    },
    {
      title: 'Task Management App',
      description: 'A collaborative task management application with real-time updates, drag-and-drop functionality, and team collaboration features. Helps teams organize and track their work efficiently.',
      technologies: ['React', 'TypeScript', 'Firebase', 'Material-UI', 'Redux'],
      liveUrl: 'https://example-taskapp.com',
      githubUrl: 'https://github.com/username/task-management',
      imageUrl: '/project2.jpg',
      featured: true
    },
    {
      title: 'Weather Dashboard',
      description: 'A responsive weather dashboard that provides real-time weather information, forecasts, and interactive maps. Features location-based weather updates and beautiful data visualizations.',
      technologies: ['JavaScript', 'HTML5', 'CSS3', 'Weather API', 'Chart.js'],
      liveUrl: 'https://example-weather.com',
      githubUrl: 'https://github.com/username/weather-dashboard',
      imageUrl: '/project3.jpg',
      featured: false
    },
    {
      title: 'Social Media Analytics',
      description: 'An analytics dashboard for social media metrics and insights. Provides comprehensive data visualization, trend analysis, and reporting features for social media managers.',
      technologies: ['React', 'D3.js', 'Node.js', 'PostgreSQL', 'REST APIs'],
      liveUrl: 'https://example-analytics.com',
      githubUrl: 'https://github.com/username/social-analytics',
      imageUrl: '/project4.jpg',
      featured: false
    },
    {
      title: 'Portfolio Website',
      description: 'A modern, responsive portfolio website showcasing personal projects and skills. Features smooth animations, dark mode support, and optimized performance.',
      technologies: ['React', 'TypeScript', 'Tailwind CSS', 'Framer Motion'],
      liveUrl: 'https://example-portfolio.com',
      githubUrl: 'https://github.com/username/portfolio-site',
      imageUrl: '/project5.jpg',
      featured: false
    },
    {
      title: 'Blog Platform',
      description: 'A full-stack blogging platform with markdown support, user authentication, and comment system. Features rich text editing and SEO optimization.',
      technologies: ['Next.js', 'MongoDB', 'Tailwind CSS', 'NextAuth', 'MDX'],
      liveUrl: 'https://example-blog.com',
      githubUrl: 'https://github.com/username/blog-platform',
      imageUrl: '/project6.jpg',
      featured: false
    }
  ]);

  const [filter, setFilter] = useState<string>('all');

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const response = await fetch('/api/projects');
        if (response.ok) {
          const data = await response.json();
          if (data && data.length > 0) {
            setProjects(data);
          }
        }
      } catch (error) {
        console.log('Using default projects, API not available');
      }
    };

    fetchProjects();
  }, []);

  const filteredProjects = filter === 'all' 
    ? projects 
    : projects.filter(project => project.featured);

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const target = e.target as HTMLImageElement;
    target.src = 'data:image/svg+xml;base64,';
  };

  return (
    <div className="projects">
      <div className="container">
        <h1 className="page-title">My Projects</h1>

        <div className="filter-section">
          <button 
            className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            All Projects
          </button>
          <button 
            className={`filter-btn ${filter === 'featured' ? 'active' : ''}`}
            onClick={() => setFilter('featured')}
          >
            Featured Only
          </button>
        </div>

        <div className="projects-grid">
          {filteredProjects.map((project, index) => (
            <div key={project._id || index} className="project-card">
              <div className="project-image">
                <img 
                  src={project.imageUrl} 
                  alt={project.title}
                  onError={handleImageError}
                />
                {project.featured && (
                  <span className="featured-badge">Featured</span>
                )}
              </div>

              <div className="project-content">
                <h3>{project.title}</h3>
                <p className="project-description">{project.description}</p>

                <div className="project-technologies">
                  {project.technologies.map((tech, techIndex) => (
                    <span key={techIndex} className="tech-tag">{tech}</span>
                  ))}
                </div>

                <div className="project-links">
                  <a 
                    href={project.liveUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-primary"
                  >
                    Live Demo
                  </a>
                  <a 
                    href={project.githubUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-secondary"
                  >
                    View Code
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredProjects.length === 0 && (
          <div className="no-projects">
            <p>No projects found for the selected filter.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Projects;
